MERGE INTO CONSULTAS FIN USING (SELECT '002390SubEfectivoUsoRestringido' INFORME ,TO_CLOB(q'[SELECT 
CODIGO, NOMBRE, 
SALDOs$mesFinal$s AS SALDOCOM
 FROM
 PLAN_CONTABLE
 WHERE ANO = s$anioFinal$s AND CODIGO LIKE '1132%'  and MOSTRAR_EN_FLUJO= '-1' AND SALDOs$mesFinal$s>0]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);
 
 MERGE INTO CONSULTAS_SUB FIN USING (SELECT '002396FlujoEfectivo' INFORME_PADRE, '002390SubEfectivoUsoRestringido' INFORME_HIJO, 'PR_STRSQL_SUBEFECTIVORESTRINGIDO' PARAMETRO ,'mrosero' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (FIN.INFORME_PADRE = INI.INFORME_PADRE AND INI.INFORME_HIJO = FIN.INFORME_HIJO)  WHEN MATCHED THEN  UPDATE SET FIN.PARAMETRO = INI.PARAMETRO , FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME_PADRE,INFORME_HIJO, PARAMETRO,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME_PADRE,INI.INFORME_HIJO, INI.PARAMETRO,INI.CREATED_BY,SYSDATE);